import React from 'react';

const Card = ({title, value, children})=>{
  return (
    <div className="card">
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>
        <div>
          <div className="kpi-muted">{title}</div>
          <div className="kpi">{value}</div>
        </div>
        <div>{children}</div>
      </div>
    </div>
  );
}
export default Card;
